// Pull both ensures `forall|p|` instances into the proof context so their
// triggers line up across the two runs (post1_self_ for r1, post2_self_ for r2).
assert(forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && p != r1 ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    post2_self_.page_is_mapped(p) && p != r2 ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

// Re-state the set-extensionality equalities from the two ensures clauses so
// that z3 sees them as ground facts in both runs (`=~=` triggers ext-equal).
assert(post1_self_.free_pages_2m() =~= pre_self_.free_pages_2m().remove(r1));
assert(post2_self_.free_pages_2m() =~= pre_self_.free_pages_2m().remove(r2));
assert(post1_self_.free_pages_4k() =~= pre_self_.free_pages_4k());
assert(post2_self_.free_pages_4k() =~= pre_self_.free_pages_4k());
assert(post1_self_.free_pages_1g() =~= pre_self_.free_pages_1g());
assert(post2_self_.free_pages_1g() =~= pre_self_.free_pages_1g());
assert(post1_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k());
assert(post2_self_.allocated_pages_4k() =~= pre_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m() =~= pre_self_.allocated_pages_2m());
assert(post2_self_.allocated_pages_2m() =~= pre_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= pre_self_.allocated_pages_1g());
assert(post2_self_.allocated_pages_1g() =~= pre_self_.allocated_pages_1g());
assert(post1_self_.mapped_pages_4k() =~= pre_self_.mapped_pages_4k());
assert(post2_self_.mapped_pages_4k() =~= pre_self_.mapped_pages_4k());
assert(post1_self_.mapped_pages_2m() =~= pre_self_.mapped_pages_2m().insert(r1));
assert(post2_self_.mapped_pages_2m() =~= pre_self_.mapped_pages_2m().insert(r2));
assert(post1_self_.mapped_pages_1g() =~= pre_self_.mapped_pages_1g());
assert(post2_self_.mapped_pages_1g() =~= pre_self_.mapped_pages_1g());
assert(post1_self_.page_mappings(r1) =~= Set::<(Pcid, VAddr)>::empty().insert((pcid, va)));
assert(post2_self_.page_mappings(r2) =~= Set::<(Pcid, VAddr)>::empty().insert((pcid, va)));
assert(post1_self_.page_io_mappings(r1) =~= Set::<(IOid, VAddr)>::empty());
assert(post2_self_.page_io_mappings(r2) =~= Set::<(IOid, VAddr)>::empty());
